window.__QUIZ_DATA__=[{"id":"objective>Agricultural Science>2012>1","subject":"Agricultural Science","year":"2012","type":"Objective","topic":"BASIC CONCEPTS : PROBLEMS OF AGRICULTURAL DEVELOPMENT AND POSSIBLE SOLUTIONS","question":"Agriculture production in west Africa can be improved by the following practices  except  the","images":[],"options":{"A":"Use of modern farm implements by farmers.","B":"legislation of communal land holding system.","C":"application of proven agricultural research findings","D":"supply of improved seeds and livestock to farmers."},"answer":"B","explanation":"The legislation of communal land holding system is not a direct method of improving agricultural production. While it can help in resolving land disputes, it does not directly contribute to the improvement of agricultural practices or yield. The other options such as the use of modern farm implements, application of proven agricultural research findings, and supply of improved seeds and livestock are all direct methods that can enhance agricultural production.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2012>2","subject":"Agricultural Science","year":"2012","type":"Objective","topic":"AGRICULTURAL ECOLOGY : FACTORS AFFECTING LAND AVAILABILITY FOR AGRICULTURAL PURPOSE","question":"A limitation to pratice of shifting cultivation in modern day agriculture is","images":[],"options":{"A":"prevalence of crop diseases","B":"farm mechanization","C":"population pressure","D":"nomadic agriculture"},"answer":"C","explanation":"The practice of shifting cultivation is limited by population pressure. Shifting cultivation involves moving from one piece of land to another after a few years to allow the land to regain its fertility. However, with increasing population, the availability of land for such practice is reducing. The other options like prevalence of crop diseases, farm mechanization, and nomadic agriculture do not directly limit the practice of shifting cultivation.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2012>3","subject":"Agricultural Science","year":"2012","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : AGRICULTURAL FINANCE","question":"Government finances agriculture through the following means  except","images":[],"options":{"A":"reduction of tariffs on agricultural inputs.","B":"granting of subsides to farmers","C":"establishing of agricultural colleges","D":"establishment of credit sources"},"answer":"C","explanation":"The ways by which government finances agriculture include:   - Reduction of tariffs on agriculture input - Granting of subsidies to farmer.  - Establishment of credit sources.  * Establishment of agricultural colleges is not the way by which government development finances Agriculture.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2012>4","subject":"Agricultural Science","year":"2012","type":"Objective","topic":"BASIC CONCEPTS : PROBLEMS OF AGRICULTURAL DEVELOPMENT AND POSSIBLE SOLUTIONS","question":"The following are factors that affects agricultural development in west Africa  except","images":[],"options":{"A":"transportation","B":"rainfall","C":"land tenure","D":"pests and diseases"},"answer":"B","explanation":"Rainfall does not affect agricultural development in West Africa. In fact, it is a crucial factor for agricultural development as it provides the necessary water for crop growth. The other options, transportation, land tenure, pests and diseases, are all factors that can hinder agricultural development.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2012>5","subject":"Agricultural Science","year":"2012","type":"Objective","topic":"AGRICULTURAL ECOLOGY : SOIL FORMATION AND PROFILE DEVELOPMENT","question":"Termites are useful in agriculture because they","images":[],"options":{"A":"help control plant population","B":"increase soil moisture","C":"improves soil aeration","D":"regulate soil temperature"},"answer":"C","explanation":"Termites improve soil aeration by creating tunnels in the soil as they move around, which allows air to circulate better. This is beneficial for plant roots, which need oxygen to grow.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2012>6","subject":"Agricultural Science","year":"2012","type":"Objective","topic":"AGRICULTURAL ECOLOGY : SOIL FORMATION AND PROFILE DEVELOPMENT","question":"A fresh soil sample of mass 180g had a mass of 120g after oven-drying. determine the percentage water content of the soil","images":[],"options":{"A":"40.4%","B":"38.8%","C":"35.3%","D":"33.3%"},"answer":"D","explanation":"Given that,  Mass of fresh soil = 180g  mass of dryed soil = 120g  Water content = 180g-120g                           =60g   % water content = 60/180 * 100                                                   = 33.3%","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2012>7","subject":"Agricultural Science","year":"2012","type":"Objective","topic":"AGRICULTURAL ECOLOGY : SOIL FORMATION AND PROFILE DEVELOPMENT","question":"The earthworm is important to the farmer because it","images":[],"options":{"A":"improves soil texture","B":"destroys soil pathogen","C":"checks soil erosion","D":"improves soil structure"},"answer":"D","explanation":"Earthworms are beneficial to farmers because they improve soil structure. As they burrow, they mix and aerate the soil, creating channels that enhance the soil's ability to absorb water and air. This process improves the soil's structure, making it more conducive for plant growth.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2012>8","subject":"Agricultural Science","year":"2012","type":"Objective","topic":"AGRICULTURAL ECOLOGY : SOIL FORMATION AND PROFILE DEVELOPMENT","question":"The soil water that is readily available for absorption by plant roots is called","images":[],"options":{"A":"capillary water","B":"gravitational water","C":"hygroscopic water","D":"superfluous water"},"answer":"A","explanation":"Capillary water is the soil water that is readily available for absorption by plant roots. It is held in the soil by capillary forces and is located in the micropores of the soil. This water can move in any direction and is readily available for plant uptake.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2012>9","subject":"Agricultural Science","year":"2012","type":"Objective","topic":"AGRICULTURAL ECOLOGY : AGRO-ALLIED INDUSTRIES AND RELATIONSHIP BETWEEN AGRICULTURE AND INDUSTRY","question":"Farmer practise mixed farming because they can","images":[],"options":{"A":"easily secure loan to expand their farms.","B":"specialize in either the growing of crops or rearing of animals","C":"use the manure from the animals to fertilize their crops","D":"easily control pest sand diseases on their crop"},"answer":"C","explanation":"Farmers practise mixed farming because they can use the manure from the animals to fertilize their crops.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2012>10","subject":"Agricultural Science","year":"2012","type":"Objective","topic":"AGRICULTURAL ECOLOGY : TYPES, COMPOSITION AND PROPERTIES OF SOIL","question":"Three soils samples labelled x, y and z were put separately in three funnels plugged with cotton wool and placed in graduated cylinders. An equal volume of water was poured on  each  soil sample. It was later observed that the amount of water that passed through soil sample X was more than that of Y and that of Y was more than that of Z. use this information to answer question  10 .   Which of the following statements is a correct deduction from the information?","images":[],"options":{"A":"x  is clay,  y  is sand and  z  is loam","B":"x  is sand,  y  is clay and  z  is loam","C":"x  is loam,  y  is sand and z is clay","D":"x is sand,  y  is loam and  z  is clay"},"answer":"D","explanation":"X= Sand, Y= Loam, Z= Clay   X (Sand): Sand has large particles and drains water quickly, making it poor at retaining moisture but good for aeration. It feels gritty and doesn't hold nutrients well.    Y (Loam): Loam is a balanced mixture of sand, silt, and clay, making it ideal for plant growth. It retains moisture and nutrients well while still allowing good drainage and aeration.    Z (Clay): Clay has very fine particles and retains water and nutrients well, but it drains poorly and can become compacted, making it hard for roots to penetrate and air to circulate.","marks":"1","difficulty":"3"},{"id":"objective>Agricultural Science>2012>11","subject":"Agricultural Science","year":"2012","type":"Objective","topic":"AGRICULTURAL ECOLOGY : PLANT NUTRIENTS AND NUTRIENT CYCLE","question":"The diagram represents the","images":["data:image/png;base64,"],"options":{"A":"nitrogen cycle","B":"kreb cycle","C":"water cycle","D":"carbon cycle"},"answer":"D","explanation":"The diagram in the question shows some biological processes and phenomena related to carbon. The diagram shows the different routes in the usage and release of carbon into the atmosphere. Some of these biological processes include photosynthesis(usuage of carbon based compounds), respiration(release of carbon based compounds into the atmosphere) hence, the diagram is a Carbon Cycle.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2012>12","subject":"Agricultural Science","year":"2012","type":"Objective","topic":"AGRICULTURAL ECOLOGY : PLANT NUTRIENTS AND NUTRIENT CYCLE","question":"The part of the diagram labelled  i  is","images":["data:image/png;base64,"],"options":{"A":"carbon dioxide","B":"photosynthesis","C":"plant","D":"nitrification"},"answer":"C","explanation":"A plant is a living organism that belongs to the kingdom Plantae. It typically has the following characteristics:  Photosynthesis: Plants make their own food by converting sunlight, carbon dioxide, and water into energy (glucose) through photosynthesis.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2012>13","subject":"Agricultural Science","year":"2012","type":"Objective","topic":"CROP PRODUCTION : CLASSIFICATION OF CROPS","question":"Which of the following factors should be considered in selecting crops? The cover crops must   I. be easy to propagate II. complete with the main crops III. have roots capable of binding soils   IV. be slow growing","images":[],"options":{"A":"I and II only","B":"II and III only","C":"I and III only","D":"III and IV only"},"answer":"C","explanation":"Factors to be considered in selecting cover crops are:   - To be easy to propagate   - Have roots capable of binding soils.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2012>14","subject":"Agricultural Science","year":"2012","type":"Objective","topic":"AGRICULTURAL ECOLOGY : IRRIGATION","question":"Which of the following terms is not associated with surface irrigation?","images":[],"options":{"A":"Tie","B":"Basin","C":"Dyke","D":"Furrow"},"answer":"A","explanation":"The following terms associated with surface irrigation  - Basin - Dyke -Furrow.  Tile is not associated to surface irrigation.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2012>15","subject":"Agricultural Science","year":"2012","type":"Objective","topic":"AGRICULTURAL ECOLOGY : PLANT NUTRIENTS AND NUTRIENT CYCLE","question":"Loss of nitrogen from the soil through the removal of oxygen from the nitrates by bacteria is known as","images":[],"options":{"A":"ammonification","B":"dehydration","C":"denitrification","D":"nitrification"},"answer":"C","explanation":"Denitrification is the loss of nitrogen from the soil through the removal of oxygen from nitrates by bacteria.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2012>16","subject":"Agricultural Science","year":"2012","type":"Objective","topic":"CROP PROTECTION : WEEDS","question":"Which of the following statements are advantages of mulching? It I. controls weeds II. conserves soil moisture   III. increases soil temperature IV. reduces soil pH","images":[],"options":{"A":"I and II only","B":"I and III only","C":"II and IV only","D":"III and IV only"},"answer":"A","explanation":"Mulching is a practice used in farming to control weeds and conserve soil moisture. It does not necessarily increase soil temperature or reduce soil pH. Therefore, the correct answer is I and II only.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2012>17","subject":"Agricultural Science","year":"2012","type":"Objective","topic":"AGRICULTURAL ECOLOGY : PLANT NUTRIENTS AND NUTRIENT CYCLE","question":"Determine the weight of potassium in a 50 kg NPK (20:20:10) bag of fertilizer","images":[],"options":{"A":"5.0 kg","B":"7.0 kg","C":"10.0 kg","D":"20.0 kg"},"answer":"C","explanation":"N : P : K (20:20:10): the weight of potassium in the fertilizer is 10kg while nitrogen and phosphorus are 20kg.","marks":"1","difficulty":"3"},{"id":"objective>Agricultural Science>2012>18","subject":"Agricultural Science","year":"2012","type":"Objective","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : FARM POWER","question":"The farm power which is most adaptable to farm operation in West Africa is","images":[],"options":{"A":"animal power","B":"wind power","C":"human power","D":"solar power"},"answer":"A","explanation":"The most adaptable farm power to farm operation in West Africa is animal power. This is because the majority of farmers in West Africa are small-scale farmers who cannot afford expensive machinery. Animals such as donkeys, horses, and oxen are used to plow the fields, carry loads, and perform other farm tasks. This makes farming more efficient and less labor-intensive for the farmers.","marks":"1","difficulty":"3"},{"id":"objective>Agricultural Science>2012>19","subject":"Agricultural Science","year":"2012","type":"Objective","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : FARM SURVEYING","question":"The diagram below represents a chain measurement drawing of a school farmland surveyed by students who encountered an obstruction at point C.         Use the diagram and the information provided to answer questions    The distance between point A and B will be given by","images":["data:image/png;base64,"],"options":{"A":"AC + CD + EB","B":"CD + DE + EB","C":"AC + CE + EB","D":"AC + CD + DE + EB"},"answer":"D","explanation":"This distance between point A and B is given by     AC+CD+DE+EB","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2012>20","subject":"Agricultural Science","year":"2012","type":"Objective","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : FARM SURVEYING","question":"The diagram below represents a chain measurement drawing of a school farmland surveyed by students who encountered an obstruction at point C.         Use the diagram and the information provided to answer questions   How would the distance CE be calculated over the obstruction?","images":["data:image/png;base64,"],"options":{"A":"CE = CD2 + EB2","B":"CE = CD2 + DE2","C":"\u221a CD2+DE2","D":"CE = \u221aDE2"},"answer":"C","explanation":"The distances of CE can be  calculated over the obstruction  CE= \u221a CD2 + DE2  .","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2012>21","subject":"Agricultural Science","year":"2012","type":"Objective","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : FARM SURVEYING","question":"The diagram below represents a chain measurement drawing of a school farmland surveyed by students who encountered an obstruction at point C.         Use the diagram and the information provided to answer questions   The method used to calculate the distance CE is called","images":["data:image/png;base64,"],"options":{"A":"chain method","B":"right-angled method","C":"similar triangle method","D":"double perpendicular method"},"answer":"B","explanation":"To calculate the distance of CE we make use of the right-angled method","marks":"1","difficulty":"3"},{"id":"objective>Agricultural Science>2012>22","subject":"Agricultural Science","year":"2012","type":"Objective","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : FARM SURVEYING","question":"The diagram below represents a chain measurement drawing of a school farmland surveyed by students who encountered an obstruction at point C.         Use the diagram and the information provided to answer questions   What form of obstruction was encountered by the students?","images":["data:image/png;base64,"],"options":{"A":"Tree","B":"River","C":"Hill","D":"Pond"},"answer":"C","explanation":"Hill. A hill is a naturally elevated landform, smaller and less steep than a mountain. It typically has a rounded or sloping shape and rises above the surrounding terrain. Hills can form through geological processes like erosion, volcanic activity, or the movement of tectonic plates.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2012>23","subject":"Agricultural Science","year":"2012","type":"Objective","topic":"AGRICULTURAL ECOLOGY : AGRICULTURAL POLLUTION","question":"If grains are not properly dried before storage they are likely to","images":[],"options":{"A":"lose viability at a fast rate","B":"remain dormant for a long time","C":"synthesize carbohydrate during storage","D":"germinate faster when planted in the field"},"answer":"A","explanation":"If grains are not properly dried before storage, they are likely to lose viability at a fast rate. This is because moisture encourages the growth of fungi and other microorganisms that can damage the grains and reduce their quality. Drying grains properly before storage helps to preserve their quality and extend their shelf life.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2012>24","subject":"Agricultural Science","year":"2012","type":"Objective","topic":"CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS","question":"Which of the following combinations of activities gives the correct sequence of nursing seeds?   I. Watering of sown seeds II. Making drills with a dibber III. Covering seeds with palm fronts  IV. Sowing seeds in drills","images":[],"options":{"A":"II, IV, III and I","B":"III, II, I and IV","C":"III, IV, II and I","D":"II, III, IV and I"},"answer":"A","explanation":"Activities sequence of nursing seeds.   - making drills with a dibber - sowing seeds in drills - covering seeds with palm fronds - watering of sown seeds","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2012>25","subject":"Agricultural Science","year":"2012","type":"Objective","topic":"CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS","question":"If the recommended spacing for a tree crop is 2.5 m by 4.0 m, how many seedlings are required to plant a 2-hectare farmland?","images":[],"options":{"A":"8,000 seedlings","B":"3,000 seedlings","C":"2,000 seedlings","D":"1,000 seedlings"},"answer":"C","explanation":"Noofseedlings=Area of landArea of crop  One hectare = 10,000 square metres  Two hectares = 2 x 10000  Area of crop = 2.5 x 4  = 10  Noofseedling=2x1000010  2000 seedlings.","marks":"1","difficulty":"3"},{"id":"objective>Agricultural Science>2012>26","subject":"Agricultural Science","year":"2012","type":"Objective","topic":"AGRICULTURAL ECOLOGY : AGRO-ALLIED INDUSTRIES AND RELATIONSHIP BETWEEN AGRICULTURE AND INDUSTRY","question":"Which of the following processes are associated with rubber production?   I. Coagulation II. Fermentation III. Tapping","images":[],"options":{"A":"I and II only","B":"I and III only","C":"II and III only","D":"I, II and III"},"answer":"B","explanation":"Rubber production involves the process of tapping the rubber tree to collect latex, a milky fluid found in the tree. The latex is then coagulated to form rubber. Fermentation is not involved in the production of rubber. Therefore, the processes associated with rubber production are I. Coagulation and III. Tapping.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2012>27","subject":"Agricultural Science","year":"2012","type":"Objective","topic":"CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS","question":"The following crops required staking except","images":[],"options":{"A":"tomato","B":"yam","C":"pumpkin","D":"guinea corn"},"answer":"D","explanation":"Staking is a method used to support the growth of plants. It is commonly used for plants that have a weak stem or those that are heavy with fruits. Among the options given, guinea corn does not require staking as it has a strong stem that can support its growth. Therefore, option 4 is correct.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2012>28","subject":"Agricultural Science","year":"2012","type":"Objective","topic":"CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS","question":"Which of the following statements is/are correct? Yams stored in barns should be inspected at least once a week to  I. remove rotten tubers II. remove sprouts from the rubbers III. prevent mouldiness in the rubbers","images":[],"options":{"A":"I only","B":"II only","C":"III only","D":"I, II and III"},"answer":"D","explanation":"The following practices are done in the storage of yam   - yams stored in barns should be inspected at least once a week  i. To remove rotten tubers  ii. To remove sprouts from tubers.  iii. Prevent mouldiness in the tubers.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2012>29","subject":"Agricultural Science","year":"2012","type":"Objective","topic":"CROP PROTECTION : WEEDS","question":"The frequency of weed control on a tomato farm does not depend on","images":[],"options":{"A":"rainfall","B":"soil fertility","C":"nearness to homestead","D":"planting distance of crops"},"answer":"C","explanation":"The frequency of weed control on a tomato farm depends on factors such as rainfall, soil fertility, and planting distance of crops. However, the nearness to a homestead does not directly affect the frequency of weed control. Weeds grow due to conditions like availability of water, sunlight, and nutrients, not proximity to a homestead.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2012>30","subject":"Agricultural Science","year":"2012","type":"Objective","topic":"CROP PRODUCTION : CROP IMPROVEMENT","question":"Citrus is usually propagated by","images":[],"options":{"A":"Budding","B":"layering","C":"use of stem cutting","D":"Uses of bulbs"},"answer":"A","explanation":"Citrus is usually propagated by budding. This is a type of grafting where a bud is taken from one plant and grown on another. This method is commonly used for citrus because it allows for the propagation of plants that are true to type, meaning they retain all the characteristics of the parent plant.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2012>31","subject":"Agricultural Science","year":"2012","type":"Objective","topic":"CROP PRODUCTION : CLASSIFICATION OF CROPS","question":"The botanical name of groundnut is","images":[],"options":{"A":"Vigna unguiculata","B":"Arachis hypogaea","C":"Phaseolus vulgaris","D":"Glycine max"},"answer":"B","explanation":"The botanical name for groundnut is  Arachis hypogaea . Botanical names are the scientific names given to plants and are universally accepted and used to avoid confusion that can be caused by common names, which vary by region and language.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2012>32","subject":"Agricultural Science","year":"2012","type":"Objective","topic":"ORNAMENTAL PLANTS :","question":"Ornamental plants reduce noise pollution in the environment by","images":[],"options":{"A":"scattering sound energy","B":"reflecting sound waves","C":"dispersing sound waves","D":"absorbing sound energy"},"answer":"D","explanation":"Ornamental plants reduce noise pollution in the environment by absorbing sound energy. The leaves, stems, and branches of plants can absorb, deflect, refract, and reflect sound waves, thereby reducing noise levels.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2012>33","subject":"Agricultural Science","year":"2012","type":"Objective","topic":"CROP PROTECTION : DISEASES OF CROPS","question":"Which of the following statements about the effects of diseases on crops are true? Reduction in I. quality of produce II. photosynthetic ability III. cost of production IV. yield of the produce","images":[],"options":{"A":"I and II only","B":"I and III only","C":"I, II and III only","D":"I, II and IV only"},"answer":"D","explanation":"The effects of diseases on crops are:    Reduction in the quality of produce   Reduction in the photosynthetic ability   Reduction in the yield of the produce.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2012>34","subject":"Agricultural Science","year":"2012","type":"Objective","topic":"CROP PROTECTION : PESTS OF CROPS","question":"Which of the following insect-pest possesses biting and chewing mouthparts?","images":[],"options":{"A":"Grasshopper","B":"Weevil","C":"Aphid","D":"Cotton stainer"},"answer":"A","explanation":"Grasshopper- bitting and chewing  Cotton stainer -sucking     weevil - chewing                            Aphid- sucking","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2012>35","subject":"Agricultural Science","year":"2012","type":"Objective","topic":"CROP PROTECTION : WEEDS","question":"Striga spp is parasitic weed of","images":[],"options":{"A":"cotton","B":"orange","C":"groundnut","D":"sorghum"},"answer":"D","explanation":"Striga spp, also known as witchweed, is a parasitic weed that primarily affects cereal crops, particularly sorghum. It is not a common parasite of cotton, orange, or groundnut.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2012>36","subject":"Agricultural Science","year":"2012","type":"Objective","topic":"FORESTRY : FOREST MANAGEMENT","question":"The first activity to undertake before establishing a plantation is","images":[],"options":{"A":"survey the land","B":"clear the land","C":"prepare the seed beds","D":"raise seedlings"},"answer":"A","explanation":"The first activity to undertake before establishing a plantation is to survey the land. This involves assessing the land to determine its suitability for the intended crop, including factors such as soil type, topography, and climate. Clearing the land, preparing the seed beds, and raising seedlings are subsequent steps that follow after the initial land survey.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2012>37","subject":"Agricultural Science","year":"2012","type":"Objective","topic":"CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS","question":"Fruits should be harvested at the appropriate time order to","images":[],"options":{"A":"prevent them from bruising","B":"minimize sugar content","C":"reap increased fruiting","D":"ensure good quality produce"},"answer":"D","explanation":"Fruits should be harvested at the appropriate time to ensure good quality produce. Harvesting fruits at the right time ensures that they have reached their optimal ripeness and nutritional content. This also ensures that the fruits have the best taste and texture, making them more appealing to consumers.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2012>38","subject":"Agricultural Science","year":"2012","type":"Objective","topic":"AGRICULTURAL ECOLOGY : AGRO-ALLIED INDUSTRIES AND RELATIONSHIP BETWEEN AGRICULTURE AND INDUSTRY","question":"Which of the following crops are useful to the soap-making industry?  I. kolanut II. Coconut III. Shea nut","images":[],"options":{"A":"I and II only","B":"I and III only","C":"II and III only","D":"I, II and III only"},"answer":"C","explanation":"Coconut and Shea nut are useful to the soap-making industry. Coconut oil is often used in soap-making for its excellent lathering and moisturizing properties. Shea nut, on the other hand, is used for its moisturizing and nourishing properties. Kolanut is not typically used in soap-making.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2012>39","subject":"Agricultural Science","year":"2012","type":"Objective","topic":"ANIMAL PRODUCTION : RANGELAND AND PASTURE MANAGEMENT","question":"An advantage of rational grazing is that","images":[],"options":{"A":"less labour is required","B":"there is greater potential for extending the grazing season","C":"animals obtain all the different kinds of forage","D":"animals can graze without danger of pest attack"},"answer":"B","explanation":"One of the advantage of rotational grazing is there is greater potential for extending the grazing season .","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2012>40","subject":"Agricultural Science","year":"2012","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL NUTRITION","question":"A sheep gained 20 kg of weight after consuming 60 kg of feed. Determine the feed conversion ratio","images":[],"options":{"A":"1:2","B":"2:3","C":"3:1","D":"5:4"},"answer":"C","explanation":"Feed conversation ration - feed consume: weight gained                                                                 60: 20                                                                   3: 1","marks":"1","difficulty":"3"},{"id":"objective>Agricultural Science>2012>41","subject":"Agricultural Science","year":"2012","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL HEALTH MANAGEMENT","question":"A disease which affects poultry only is","images":[],"options":{"A":"coccidiosis","B":"newcastle","C":"Fowl pox","D":"helminthiasis"},"answer":"C","explanation":"Fowl pox disease is the only disease that affect poultry only.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2012>42","subject":"Agricultural Science","year":"2012","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL NUTRITION","question":"Which of the following factors have negative influence on egg weight? I. High environmental temperature II. Poor lighting III. Comb size","images":[],"options":{"A":"I and II only","B":"I and III only","C":"II and III only","D":"I, II and III"},"answer":"A","explanation":"High environment temperature and poor lighting are factor that have negative influence on egg weight","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2012>43","subject":"Agricultural Science","year":"2012","type":"Objective","topic":"ANIMAL PRODUCTION : AQUACULTURE","question":"Fish ponds in arid areas should be deeper than those in the rain forest in order to","images":[],"options":{"A":"ensure rapid growth of fish in arid areas","B":"prevent loss of fish through extreme of temperatures","C":"provide sufficient nutrients for the survival of fish","D":"prevent exposure of fish to direct effect of the sun"},"answer":"B","explanation":"Fish pond in land area are usually deeper than those in the humid (rainforests) in other to prevent loss of fish through extreme temperatures .","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2012>44","subject":"Agricultural Science","year":"2012","type":"Objective","topic":"ANIMAL PRODUCTION : LIVESTOCK MANAGEMENT","question":"In sheep production, litter is put on the floor mainly to","images":[],"options":{"A":"reduce the build-up of ectoparasites","B":"facilitate cleaning of the house","C":"reduce the incidence of pneumonia in lambs","D":"help maintain suitable humidity in the house"},"answer":"C","explanation":"In sheep production, litter, such as straw or wood shavings, is placed on the floor mainly to help reduce the incidence of pneumonia in lambs.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2012>45","subject":"Agricultural Science","year":"2012","type":"Objective","topic":"ANIMAL PRODUCTION : LIVESTOCK MANAGEMENT","question":"Determine the number of pigs that can be housed in a pigsty measuring 5.0 m by 4.0 m, if the floor space for a pig is 2.0 m2","images":[],"options":{"A":"10","B":"11","C":"20","D":"40"},"answer":"A","explanation":"The number of pigs that can be housed in a pigsty measuring 5.0 m by 4.0 m, if the floor space for a pig is 2.0 m2, can be determined by dividing the total floor space by the space required per pig. The total floor space is 5.0 m * 4.0 m = 20.0 m2. Dividing this by the space required per pig (2.0 m2) gives 10 pigs.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2012>46","subject":"Agricultural Science","year":"2012","type":"Objective","topic":"CROP PROTECTION : WEEDS","question":"The type of weed control involved when tilapia feeds on aquatic weeds is","images":[],"options":{"A":"biological","B":"chemical","C":"cultural","D":"mechanical"},"answer":"A","explanation":"The type of weed control involved when tilapia feeds on aquatic weeds is biological. This is because the tilapia, a living organism, is used to control the weeds. Biological weed control is a method of controlling weeds using other living organisms.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2012>47","subject":"Agricultural Science","year":"2012","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL IMPROVEMENT","question":"Which of the following statements about cross breeding in farm animal is  false ?","images":[],"options":{"A":"It is a method used to produce new breeds of farm animals","B":"The individuals used have all characters in common","C":"It is a practice of improving poultry production","D":"It can be used to introduce new genes in farm animals"},"answer":"B","explanation":"The statement 'The individuals used have all characters in common' is false. Cross breeding involves the mating of animals from different breeds, so they do not have all characters in common. The purpose of cross breeding is to combine the desirable traits of two different breeds.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2012>48","subject":"Agricultural Science","year":"2012","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL IMPROVEMENT","question":"On which of the following criteria is pedigree selection in animal improvement based?","images":[],"options":{"A":"Performance of the ancestors","B":"Characteristics of the sire","C":"Performance of the offspring","D":"Characteristics of the dam"},"answer":"A","explanation":"Pedigree selection in animal improvement is based on the performance of the ancestors. This method involves selecting animals based on the performance or traits of their ancestors. The assumption is that desirable traits can be passed from the ancestors to the offspring.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2012>49","subject":"Agricultural Science","year":"2012","type":"Objective","topic":"ANIMAL PRODUCTION : ANATOMY AND PHYSIOLOGY OF FARM ANIMALS","question":"Use the animal body parts listed below to answer questions 49 and 51.   I. Cowper's gland II. Jejunum III. Urethra    Which of the animal body parts listed above are related to the reproduction system?","images":[],"options":{"A":"I and II only","B":"I and III only","C":"II and III only","D":"I, II and III"},"answer":"B","explanation":"The Cowper's gland and Urethra are part of the male reproductive system. The Jejunum is part of the digestive system, not the reproductive system.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2012>50","subject":"Agricultural Science","year":"2012","type":"Objective","topic":"ANIMAL PRODUCTION : ANATOMY AND PHYSIOLOGY OF FARM ANIMALS","question":"Use the animal body parts listed below to answer questions 49 and 51.   I. Cowper's gland II. Jejunum III. Urethra   Which of the following body part is found in female animals","images":[],"options":{"A":"I and II only","B":"I and III only","C":"II and III only","D":"I, II, and III"},"answer":"C","explanation":"Jejunum  and urethra are found in the female animals but cowper's gland is found in females but cowper's gland in males.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2012>51","subject":"Agricultural Science","year":"2012","type":"Objective","topic":"ANIMAL PRODUCTION : ANATOMY AND PHYSIOLOGY OF FARM ANIMALS","question":"Which of the animal body parts listed above secrets substances?","images":[],"options":{"A":"I and II only","B":"I and III only","C":"II and III only","D":"I, II and III"},"answer":"A","explanation":"The Cowper's gland secretes a fluid that lubricates and neutralizes acidic conditions in the urethra. The Jejunum secretes digestive enzymes and absorbs nutrients from food. The Urethra does not secrete substances, it is a duct that carries urine from the bladder and semen from the ejaculatory ducts out of the body.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2012>52","subject":"Agricultural Science","year":"2012","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL HEALTH MANAGEMENT","question":"Which of the following symptoms is typical of louse infestation in livestock?","images":[],"options":{"A":"Itching of the body","B":"Abdominal pain","C":"Profuse salivation","D":"Oozing out of blood"},"answer":"A","explanation":"Lice infestation in livestock is typically characterized by itching of the body. This is because lice are ectoparasites that feed on the skin and blood of the host animal, causing irritation and itching.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2012>53","subject":"Agricultural Science","year":"2012","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL NUTRITION","question":"Which of the following statements about herbivores are true?   I. Non-ruminant herbivores have long caeca II. Non-ruminant herbivores have complex stomach III. Ruminant herbivores chew the cud","images":[],"options":{"A":"I and II only","B":"I and III only","C":"II and III only","D":"I, II and III"},"answer":"B","explanation":"Herbivores are animals that eat plants. Non-ruminant herbivores do have long caeca which helps in the digestion of cellulose. Ruminant herbivores chew the cud, a process known as rumination. However, non-ruminant herbivores do not have a complex stomach, they have a simple stomach. Therefore, statements I and III are true.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2012>54","subject":"Agricultural Science","year":"2012","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL HEALTH MANAGEMENT","question":"If an injured goat bleeds without the blood clotting, it is likely that the goat is deficient in","images":[],"options":{"A":"vitamin D","B":"vitamin K","C":"vitamin E","D":"vitamin C"},"answer":"B","explanation":"Vitamin K is essential for the synthesis of certain proteins that help in blood clotting. If an animal is deficient in Vitamin K, it may bleed excessively because its blood will not clot properly. Therefore, if an injured goat bleeds without the blood clotting, it is likely that the goat is deficient in Vitamin K.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2012>55","subject":"Agricultural Science","year":"2012","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : FARM MANAGER","question":"Determine the cost price of a farm equipment that has a salvage value of \u20a6500,000.00, a useful life of 10 years and an annual depreciation of \u20a6400,000.00","images":[],"options":{"A":"\u20a6500,000.00","B":"\u20a6900,000.00","C":"\u20a64,500,000.00","D":"\u20a65,500,000.00"},"answer":"C","explanation":"Given that  Salvage value - \u20a6500,000.  Time - 10 years  Annual depreciation - \u20a6400,000                                   - \u20a64,000,000   Cost price - Total depreciation+ salvage value                          \u20a64,000,000+\u20a6500,000                            \u20a6 4,500,000","marks":"1","difficulty":"3"},{"id":"objective>Agricultural Science>2012>56","subject":"Agricultural Science","year":"2012","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : AGRICULTURAL FINANCE","question":"An example of long-term liability of a farmer is","images":[],"options":{"A":"capital","B":"interest","C":"salary","D":"taxes"},"answer":"A","explanation":"Long-term liabilities are debts that are due more than one year in the future. In the context of a farmer, capital can be considered a long-term liability as it is the money that the farmer has invested in the farm and expects to recover over a long period of time.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2012>57","subject":"Agricultural Science","year":"2012","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : BASIC ECONOMIC PRINCIPLES","question":"A farm business makes profits when","images":[],"options":{"A":"total revenue equals total cost","B":"total cost exceeds total revenue","C":"total revenue exceeds total cost","D":"total revenue equals average cost"},"answer":"C","explanation":"Farm business will make profit when:    TR>TC  TR- TC= P   where TR- Total revenue, TC- Total cost, P- profit.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2012>58","subject":"Agricultural Science","year":"2012","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : BASIC ECONOMIC PRINCIPLES","question":"Marginal cost of production is defined as","images":[],"options":{"A":"increase in fixed cost that results from increasing production by one unit","B":"product of average variable cost and the number of units produced","C":"average physical product multiplied by the variable cost","D":"Increase in total cost as output is increased by one unit"},"answer":"D","explanation":"Marginal cost of production is the increase in total cost that comes from producing one additional unit of the product. It is derived from the variable cost of production, given that fixed costs do not change with the quantity of output. Therefore, the correct answer is 'Increase in total cost as output is increased by one unit'.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2012>59","subject":"Agricultural Science","year":"2012","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : AGRICULTURAL FINANCE","question":"The price of a fixed asset at the end of its useful life is called","images":[],"options":{"A":"salvage value","B":"depreciation value","C":"annual depreciation","D":"appreciation value"},"answer":"A","explanation":"The price of a fixed asset at the end of its useful life is referred to as its salvage value. This is the estimated resale value of an asset at the end of its useful life. It is subtracted from the cost of a fixed asset to determine the amount of the asset cost that will be depreciated. Thus, the correct answer is 'salvage value'.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2012>60","subject":"Agricultural Science","year":"2012","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : AGRICULTURAL EXTENSION","question":"Which of the following criteria are used in selecting agricultural extension teaching methods?   I. Time available for the programme II. The number of farmers involved III. The agricultural needs of the farmers","images":[],"options":{"A":"I and II only","B":"I and III only","C":"II and III only","D":"I, II and III"},"answer":"D","explanation":"Criteria to be considered in selecting agricultural extension teaching are;   -Time available for the programming  -The number of farmers involved  - The agricultural needs of the farmers","marks":"1","difficulty":"2"}];